INSERT INTO pages (id, title, subtitle, slug, content, cover_image_url, published, sort_order, seo_title, seo_description, created_at, updated_at) VALUES ('92444977-5aba-42e2-92cc-e011b906754a', 'DAFTAR REGULASI PPID', NULL, 'regulasi', 'A. Regulasi Nasional (Dasar Hukum)
1. Undang-Undang Republik Indonesia Nomor 14 Tahun 2008 tentang Keterbukaan Informasi Publik. | https://ppid.sultraprov.go.id/regulasi/uu_14_2008.pdf
2. Undang-Undang Republik Indonesia Nomor 25 Tahun 2009 tentang Pelayanan Publik. | https://peraturan.bpk.go.id/Details/38748/uu-no-25-tahun-2009
3. Peraturan Pemerintah Republik Indonesia Nomor 61 Tahun 2010 tentang Pelaksanaan Undang-Undang Nomor 14 Tahun 2008 tentang Keterbukaan Informasi Publik. | https://peraturan.bpk.go.id/Details/5095/pp-no-61-tahun-2010
4. Peraturan Komisi Informasi Nomor 1 Tahun 2010 tentang Standar Layanan Informasi Publik. | https://komisiinformasi.go.id/regulasi/perki-1-2010
5. Peraturan Komisi Informasi Nomor 1 Tahun 2013 tentang Prosedur Penyelesaian Sengketa Informasi Publik. | https://komisiinformasi.go.id/regulasi/perki-1-2013
6. Peraturan Menteri Pendidikan dan Kebudayaan Republik Indonesia Nomor 75 Tahun 2016 tentang Layanan Informasi Publik di Lingkungan Kementerian Pendidikan dan Kebudayaan. | https://jdih.kemdikbud.go.id/sso/arsip/3224/file
7. Peraturan Menteri Riset, Teknologi, dan Pendidikan Tinggi Republik Indonesia Nomor 75 Tahun 2016 tentang Layanan Informasi Publik di Lingkungan Kementerian Riset, Teknologi, dan Pendidikan Tinggi. | https://peraturan.go.id/id/permendikti-no-75-tahun-2016

B. Regulasi Internal Universitas
8. Surat Keputusan Rektor Universitas Perintis Indonesia Nomor 008A/SK-UPERTIS-YPP/I/2025 tentang Penetapan Pejabat Pengelola Informasi dan Dokumentasi (PPID) Universitas Perintis Indonesia.
9. Surat Keputusan PPID Utama Universitas Perintis Indonesia Nomor 010B/PPID-UPERTIS/I/2025 tentang Penetapan Daftar Informasi Publik (DIP) yang Telah Dimutakhirkan Tahun 2025.
10. Surat Keputusan PPID Utama Universitas Perintis Indonesia Nomor 010C/PPID-UPERTIS/I/2025 tentang Penetapan Daftar Informasi Publik yang Dikecualikan Tahun 2025.
11. Standar Operasional Prosedur (SOP) Pelayanan Informasi Publik:
* SOP Pengumuman Informasi Publik
* SOP Permohonan Informasi Publik
* SOP Pengajuan Keberatan
* SOP Pemutakhiran Daftar Informasi Publik
* SOP Pendokumentasian Informasi Publik
* SOP Maklumat Pelayanan Informasi Publik
* SOP Uji Konsekuensi

C. Regulasi Pendukungs
12. Pedoman Pengelolaan Organisasi
13. Pedoman Pengelolaan Administrasi', NULL, true, 0, 'Regulasi KIP', NULL, '2026-06-27 00:47:42.064866', '2026-06-29 17:28:56.191636');
INSERT INTO pages (id, title, subtitle, slug, content, cover_image_url, published, sort_order, seo_title, seo_description, created_at, updated_at) VALUES ('7a82e076-7f46-49fe-a99e-f30a8d4a64c5', 'Maklumat Pelayanan', NULL, 'maklumat', 'PPID Universitas Perintis Indonesia berkomitmen dalam menyelenggarakan pelayanan informasi publik sesuai dengan amanat perundang-undangan dengan tekad.

Melayani permohonan informasi publik sesuai dengan tata cara yang berlaku
Menyediakan informasi publik yang benar dan dapat dipertanggung jawabkan 
Memberikan kemudahan akses informasi publik melalui berbagai media yang mudah digunakan dengan informasi terkini
Menyiapkan dan mengumumkan daftar informasi publik
Mengevaluasi kinerja petugas pelaksana secara berkala demi memberikan pelayanan yang terbaik
menyampaikan laporan layanan informasi publik ke Komisi Informasi Sumatera Barat


Pejabat Pengelola Informasi dan Dokumentasi (PPID)
Universitas Perintis Indonesia

Dto

Ns. Yaslina, S.Kep.,M.Kep.,Sp.Kom.


Rektor Universitas Perintis Indonesia', NULL, true, 0, 'Maklumat Pelayanan', NULL, '2026-06-27 00:48:27.695558', '2026-06-29 17:28:51.247516');
INSERT INTO pages (id, title, subtitle, slug, content, cover_image_url, published, sort_order, seo_title, seo_description, created_at, updated_at) VALUES ('9047edfc-fbad-436a-82e7-e82253d57dfb', 'Zona Integrasi (ZI)', 'Pembangunan Zona Integrasi Menuju Wilayah Bebas dari Korupsi (WBK) & Wilayah Birokrasi Bersih dan Melayani (WBBM) UPERTIS', 'zona-integrasi', '{
  "intro": "",
  "sections": [
    {
