INSERT INTO pages (id, title, subtitle, slug, content, cover_image_url, published, sort_order, seo_title, seo_description, created_at, updated_at) VALUES ('c7ec74d2-c63d-479e-943d-b102356fbb9c', 'Pengajuan Keberatan Informasi', 'Mekanisme pengajuan keberatan atas layanan informasi publik PPID UPERTIS', 'keberatan-informasi', '{"intro":"{\n\t\t\"intro\": \"<p>Pemohon Informasi Publik dapat mengajukan keberatan secara tertulis kepada Atasan PPID UPERTIS jika permohonan informasi ditolak, tidak ditanggapi secara tepat waktu, atau biaya yang dikenakan terlalu tinggi. Silakan unduh formulir di bawah ini, isi dengan lengkap, lalu serahkan kepada petugas desk layanan PPID.</p>\",\n\t\t\"docs\": [\n\t\t\t{\n\t\t\t\t\"title\": \"Formulir Pengajuan Keberatan Informasi UPERTIS\",\n\t\t\t\t\"description\": \"Formulir cetak resmi pengajuan keberatan layanan informasi publik.\",\n\t\t\t\t\"file_url\": \"/uploads/formulir-keberatan-ppid.pdf\"\n\t\t\t}\n\t\t],\n\t\t\"manual_steps\": [\n\t\t\t{ \"title\": \"Pemohon Informasi\", \"desc\": \"Pemohon datang langsung ke sekretariat PPID-UPERTIS untuk mengajukan keberatan atas informasi publik yang diterima.\" },\n\t\t\t{ \"title\": \"Mengisi Form Keberatan\", \"desc\": \"Petugas informasi menerima berkas pengajuan dan pemohon mengisi formulir keberatan dengan melampirkan identitas diri berupa KTP/SIM atau surat tugas dari institusi lainnya.\" },\n\t\t\t{ \"title\": \"Menerima Tanda Terima\", \"desc\": \"Petugas informasi memberikan tanda bukti resmi bahwa pemohon telah mengajukan keberatan atas layanan informasi publik.\" },\n\t\t\t{ \"title\": \"Keberatan Di Proses\", \"desc\": \"PPID Pelaksana meneruskan pengaduan ke Rektor/PPID Utama UPERTIS untuk diproses selambat-lambatnya 30 hari kerja.\" },\n\t\t\t{ \"title\": \"Penyerahan Jawaban\", \"desc\": \"Jawaban/tanggapan tertulis atas keberatan disampaikan kepada pemohon melalui PPID Pelaksana.\" },\n\t\t\t{ \"title\": \"Layanan Selesai\", \"desc\": \"Prosedur pengajuan keberatan informasi secara manual selesai dilakukan.\" }\n\t\t],\n\t\t\"online_steps\": [\n\t\t\t{ \"title\": \"Mengunjungi Website\", \"desc\": \"Pemohon mengunjungi website resmi PPID Universitas Perintis Indonesia di ppid.upertis.ac.id.\" },\n\t\t\t{ \"title\": \"Mengunduh Form\", \"desc\": \"Pemohon mengunduh berkas formulir pengajuan keberatan (.doc) dari menu unduhan di website.\" },\n\t\t\t{ \"title\": \"Mengirimkan Berkas\", \"desc\": \"Pemohon mengirim formulir terisi beserta scan identitas (KTP/SIM) ke email resmi PPID UPERTIS di ppidcare@upertis.ac.id.\" },\n\t\t\t{ \"title\": \"Menerima Tanda Terima\", \"desc\": \"Petugas informasi mengirimkan konfirmasi tanda terima pengajuan keberatan via email.\" },\n\t\t\t{ \"title\": \"Permohonan Di Proses\", \"desc\": \"Berkas keberatan diteruskan ke Rektor UPERTIS untuk ditinjau dan diproses dalam kurun waktu 30 hari kerja.\" },\n\t\t\t{ \"title\": \"Penyerahan Jawaban\", \"desc\": \"Jawaban keputusan dari Rektor UPERTIS dikirimkan kepada pemohon melalui PPID Pelaksana.\" },\n\t\t\t{ \"title\": \"Layanan Selesai\", \"desc\": \"Prosedur pengajuan keberatan informasi secara online selesai dilakukan.\" }\n\t\t]\n\t}","docs":[{"title":"Formulir Pengajuan Keberatan Informasi UPERTIS","description":"Formulir cetak resmi pengajuan keberatan layanan informasi publik.","file_url":"/uploads/formulir-keberatan-ppid.pdf"}],"manual_steps":[{"title":"Pemohon Informasi","desc":"Pemohon datang langsung ke sekretariat PPID-UPERTIS untuk mengajukan keberatan atas informasi publik yang diterima."},{"title":"Mengisi Form Keberatan","desc":"Petugas informasi menerima berkas pengajuan dan pemohon mengisi formulir keberatan dengan melampirkan identitas diri berupa KTP/SIM atau surat tugas dari institusi lainnya."},{"title":"Menerima Tanda Terima","desc":"Petugas informasi memberikan tanda bukti resmi bahwa pemohon telah mengajukan keberatan atas layanan informasi publik."},{"title":"Keberatan Di Proses","desc":"PPID Pelaksana meneruskan pengaduan ke Rektor/PPID Utama UPERTIS untuk diproses selambat-lambatnya 30 hari kerja."},{"title":"Penyerahan Jawaban","desc":"Jawaban/tanggapan tertulis atas keberatan disampaikan kepada pemohon melalui PPID Pelaksana."},{"title":"Layanan Selesai","desc":"Prosedur pengajuan keberatan informasi secara manual selesai dilakukan."}],"online_steps":[{"title":"Mengunjungi Website","desc":"Pemohon mengunjungi website resmi PPID Universitas Perintis Indonesia di ppid.upertis.ac.id."},{"title":"Mengunduh Form","desc":"Pemohon mengunduh berkas formulir pengajuan keberatan (.doc) dari menu unduhan di website."},{"title":"Mengirimkan Berkas","desc":"Pemohon mengirim formulir terisi beserta scan identitas (KTP/SIM) ke email resmi PPID UPERTIS di ppidcare@upertis.ac.id."},{"title":"Menerima Tanda Terima","desc":"Petugas informasi mengirimkan konfirmasi tanda terima pengajuan keberatan via email."},{"title":"Permohonan Di Proses","desc":"Berkas keberatan diteruskan ke Rektor UPERTIS untuk ditinjau dan diproses dalam kurun waktu 30 hari kerja."},{"title":"Penyerahan Jawaban","desc":"Jawaban keputusan dari Rektor UPERTIS dikirimkan kepada pemohon melalui PPID Pelaksana."},{"title":"Layanan Selesai","desc":"Prosedur pengajuan keberatan informasi secara online selesai dilakukan."},{"title":"Langkah Baru","desc":"Deskripsi langkah baru"}]}', NULL, true, 5, NULL, NULL, '2026-06-28 18:23:21.391156', '2026-06-28 19:42:44.426571');
INSERT INTO pages (id, title, subtitle, slug, content, cover_image_url, published, sort_order, seo_title, seo_description, created_at, updated_at) VALUES ('68f0f0ed-2367-4231-9691-ebebde019cbf', 'Jadwal Layanans', NULL, 'jadwal-layanan-informasi', '{"senin_kamis_kerja":"08:10 – 16:00 WIB","senin_kamis_istirahat":"12:00 – 13:30 WIB","jumat_kerja":"08:00 – 15:00 WIB","jumat_istirahat":"12:00 – 14:00 WIB","sabtu_minggu":"Sistem Online Tetap Aktif 24/7 (Desk fisik Tutup)","offline_guide_1":"Membawa kartu identitas resmi (KTP untuk perorangan, Akta/SK pendirian untuk instansi).","offline_guide_2":"Loket Pelayanan berada di Lantai 1 Gedung Rektorat Kampus Utama UPERTIS Padang.","offline_guide_3":"Petugas kami siap membantu pencatatan, peninjauan berkas, hingga cetak salinan dokumen.","online_guide_1":"Gunakan menu Permohonan Informasi untuk mengisi formulir digital dan upload KTP.","online_guide_2":"Simpan nomor tiket pengajuan untuk melacak tanggapan admin secara real-time.","online_guide_3":"Jawaban atau link unduhan berkas digital akan dikirimkan langsung ke email/tiket Anda.","custom_remarks":""}', NULL, true, 0, 'Jadwal Layanans', NULL, '2026-06-26 23:35:05.58761', '2026-06-29 22:09:04.790349');
