INSERT INTO pages (id, title, subtitle, slug, content, cover_image_url, published, sort_order, seo_title, seo_description, created_at, updated_at) VALUES ('be666929-f3ab-4861-ba6d-2595486cc2cc', 'Profil', NULL, 'profil', '{"sejarah":"PROFIL PPID UNIVERSITAS PERINTIS INDONESIA\n\n\nSesuai amanat Undang-undang (UU) No 14 Tahun 2008 Tentang Keterbukaan Informasi Publik (KIP), Universitas Perintis Indonesia (UPERTIS) sebagai badan publik berupaya memenuhi kebutuhan publik akan informasi dengan membuat laman ppid.upertis.ac.id\n\n \n\nLayanan Informasi Publik UPERTIS disediakan untuk memudahkan publik mendapatkan informasi tentang UPERTSIS. Publik berhak mengajukan informasi publik yang dikelola oleh UPERTIS sesuai ketentuan-ketentuan yang berlaku. UPERTIS melayani seluruh permohonan informasi melalui Layanan Informasi Publik secara daring maupun luring. UPERTIS juga menyediakan berbagai informasi publik, yang dapat diakses dari laman website ppid.upertis.ac.id maupun website upertis.ac.id.\n\n \n\nPPID UPERTIS dibentuk berdasarkan Surat Keputusan Rektor Universitas Perintis Indonesia nomor      07a/UPERTIS-YPP/I /2023 tanggal 09Januari 2023. Latar belakang berdirinya PPID UPERTIS adalah Konsekuensi dari tuntutan reformasi di Indonesia, salah satu diantaranya adalah ditetapkannya UU N0.14 tahun 2008 tentang Keterbukaan Informasi Publik (KIP) yang bertujuan untuk mewujudkan tata kelola pemerintahan yang baik dan bertanggungjawab (good governance)\n\n \n\nBerdasarkan Surat Keputusan Rektor Nomor: 07a/UPERTIS-YPP/I/2023 tanggal 09 Januari 2023 tentang Pejabat Pengelola Informasi dan Dokumentasi (PPID) UPERTIS, Rektor universitas perintis Indoneisa Yendrizal jafri, S.Kp,.Biomed ditetapkan sebagai PPID Utama dibantu oleh dewan pertimbangan PPID, PPID Pelaksana Unit dan PPID Pelaksana Fakultas.\n\n \n\nPPID memiliki tugas dan wewenang dalam melakukan koordinasi dan harmonisasi pelaksanaan pelayanan informasi publik. PPID dalam hal ini bertanggungjawab dan berkewajiban melaporkan kegiatannya kepada Komisi Informasi dan publik","stats":[{"value":"2023","label":"TAHUN BERDIRI"}],"image1":"/uploads/media/1782728956260232800.jpg","image2":"/uploads/media/1782728965245052700.jpg","image3":"/uploads/media/1782728973813710500.jpeg"}', '/uploads/media/1782728989455705700.jpeg', true, 0, 'Profil', NULL, '2026-05-08 20:25:56.187019', '2026-06-29 17:29:52.333427');
