INSERT INTO pages (id, title, subtitle, slug, content, cover_image_url, published, sort_order, seo_title, seo_description, created_at, updated_at) VALUES ('307f6316-d0fd-4c6b-896a-a2fc39152b1e', 'Permohonan Penyelesaian Sengketa', 'Prosedur pengajuan sengketa informasi ke Komisi Informasi Sumbar', 'Permohonan-penyelesaian-sengketa', 'Prosedur pengajuan sengketa informasi publik kepada Komisi Informasi Provinsi Sumatera Barat. Pemohon dapat mengajukan secara langsung maupun mengirimkan berkas surat resmi.', NULL, true, 6, 'Permohonan Penyelesaian Sengketa - PPID UPERTIS', 'Panduan pengajuan sengketa KIP ke Komisi Informasi Sumatera Barat', '2026-06-29 17:07:10.823732', '2026-06-29 17:07:10.823732');

