INSERT INTO site_settings (key, value, updated_at) VALUES ('page_tata_nilai', '{"intro": "Tujuh Tata Nilai UPERTIS merupakan fondasi karakter yang menjiwai seluruh aktivitas akademik dan non-akademik di lingkungan Universitas Perintis Indonesia.", "values": [{"icon": "🏆", "name": "Unggul", "description": "Bahwa lulusan memiliki kemampuan berdaya saing pada taraf ASEAN dan sukses dalam karirnya."}, {"icon": "💼", "name": "Profesional", "description": "Merupakan kemampuan lulusan dalam melakukan unjuk kerja dengan menggunakan konsep, teori, metode, bahan, dan/atau instrument, yang diperoleh melalui pengalaman pembelajaran."}, {"icon": "⚖️", "name": "Etika", "description": "Bahwa lulusan memiliki nilai, norma dan etika akademik."}, {"icon": "🧠", "name": "Rasional", "description": "Bahwa lulusan memiliki sikap yang rasional untuk bertindak dalam berbagai lapisan masyarakat."}, {"icon": "💪", "name": "Tangguh", "description": "Bahwa lulusan memiliki karakter yang mampu beradaptasi dalam berbagai situasi dan kondisi, ulet dalam berbagai usaha dan upaya, serta dinamis terhadap perubahan lingkungan strategis"}, {"icon": "💎", "name": "Integritas", "description": "Bahwa lulusan memiliki nilai kejujuran ilmiah dalam bertindak sehingga karyanya dapat dipercaya."}, {"icon": "👥", "name": "Solidaritas", "description": "Bahwa lulusan menghargai perbedaan dan keragaman ras, suku, agama, budaya, dan status sosial dalam kehidupan bermasyarakat."}]}', '2026-06-12 15:18:47.555241') ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, updated_at = EXCLUDED.updated_at;
INSERT INTO site_settings (key, value, updated_at) VALUES ('campus_highlights', '{"cards": [{"title": "Laboratorium Klinik Terpadu & CBT Center Nasional", "link_url": "/halaman/fasilitas", "subtitle": "FASILITAS MODERN", "image_url": "/kampus-unpri.jpeg", "link_text": "Eksplorasi Fasilitas"}, {"items": ["Unggul", "Profesional", "Integritas", "Tangguh"], "title": "Internalisasi 7 Tata Nilai Utama UPERTIS", "link_url": "/halaman/tata-nilai", "subtitle": "KARAKTER & ETIKA", "image_url": "", "link_text": "Lihat Selengkapnya"}, {"title": "Your Dream Is Our Mission — Mimpi Anda Adalah Misi Kami", "link_url": "/halaman/visi-misi", "subtitle": "MOTTO PENDIDIKAN", "image_url": "", "link_text": "Visi & Rencana Strategis"}], "title": "Keunggulan Kampus"}', '2026-06-14 15:06:00.518445') ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, updated_at = EXCLUDED.updated_at;
