INSERT INTO site_settings (key, value, updated_at) VALUES ('page_komite_etik', '{"badge": "MENGAPA KEPK UPERTIS?", "title": "Kredibilitas Tinggi dan Proteksi Mutlak Protokol Riset Anda", "card_blue_label": "No. Registrasi KEPPKN Kemenkes RI", "card_blue_number": "0116221371", "image_top_center": "/uploads/pages/1781711421504803500.jpg", "testimonial_role": "Dekan FIKES & Peneliti Utama", "card_purple_label": "Standar Prosedur Operasional 2016", "testimonial_quote": "Proses pengujian kelayakan etik di KEPK UPERTIS sangat cepat, terstruktur, transparan, dan sepenuhnya mengacu pada standar nasional Kemenkes.", "card_purple_number": "CIOMS-WHO", "image_bottom_right": "/uploads/pages/1781711429891593400.jpg", "testimonial_author": "Dr. rer. nat. Ikhwan Resmala Sudji, M.Si", "testimonial_avatar": "/uploads/pages/1781711414806954300.jpg"}', '2026-06-17 22:50:32.46809') ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, updated_at = EXCLUDED.updated_at;
INSERT INTO site_settings (key, value, updated_at) VALUES ('page_layanan', '{"intro": "UPERTIS menyediakan berbagai layanan untuk mendukung keberhasilan akademik, pengembangan karir, dan kesejahteraan seluruh civitas akademika.", "services": [{"url": "", "icon": "🏛️", "name": "Organisasi Mahasiswa (BEM, DLM, HIMA)", "contact": "", "category": "Kemahasiswaan", "description": "Wadah kegiatan kemahasiswaan yang terdiri dari Badan Eksekutif Mahasiswa (BEM), Dewan Legislatif Mahasiswa (DLM), dan Himpunan Mahasiswa Program Studi (HIMA)."}, {"url": "", "icon": "🏆", "name": "Unit Kegiatan Mahasiswa (UKM)", "contact": "", "category": "Kemahasiswaan", "description": "Wadah pengembangan minat, bakat, dan kreativitas mahasiswa di bidang Seni, Olahraga, Kerohanian, dan Minat Khusus lainnya."}, {"url": "", "icon": "🥇", "name": "Prestasi Mahasiswa", "contact": "", "gallery": ["/uploads/pages/1782402996826552600.jpg", "/uploads/pages/1782403005301402300.jpg", "/uploads/pages/1782403009309951100.jpg"], "category": "Kemahasiswaan", "image_url": "/uploads/pages/1782402983893577400.jpg", "description": "Galeri penghargaan dan dokumentasi prestasi mahasiswa UPERTIS di tingkat wilayah, nasional, hingga internasional."}, {"url": "", "icon": "💬", "name": "Bimbingan Konseling", "contact": "", "category": "Kemahasiswaan", "description": "Layanan konseling psikologis, konsultasi pribadi, akademik, dan sosial untuk mendukung kesehatan mental mahasiswa."}, {"url": "", "icon": "📊", "name": "Tracer Study", "contact": "", "category": "Alumni", "description": "Survei pelacakan alumni untuk mengukur keterserapan lulusan di dunia kerja dan sebagai bahan evaluasi serta peningkatan mutu kurikulum."}, {"url": "", "icon": "💼", "name": "Karir & Alumni", "contact": "", "category": "Alumni", "description": "Informasi lowongan kerja, bursa karir, magang, pelatihan kesiapan kerja, dan jejaring komunikasi alumni."}, {"url": "", "icon": "🌐", "name": "Profil Kerjasama", "contact": "", "category": "Humas & Kerjasama", "description": "Informasi profil, visi, misi, dan program kerja bidang Humas dan Kerjasama Universitas Perintis Indonesia."}, {"url": "", "icon": "🤝", "name": "Mitra Kerjasama", "contact": "", "category": "Humas & Kerjasama", "description": "Daftar instansi pemerintah, swasta, rumah sakit, industri, dan universitas mitra dalam negeri maupun luar negeri."}, {"url": "https://kerjasama.upertis.ac.id/", "icon": "📝", "name": "Layanan Kerjasama", "contact": "", "category": "Humas & Kerjasama", "description": "Portal resmi layanan pengajuan kerjasama institusi dengan Universitas Perintis Indonesia."}, {"url": "", "icon": "🛡️", "name": "Profil Penjaminan Mutu", "contact": "", "category": "Penjaminan Mutu", "description": "Struktur organisasi, kebijakan mutu, dan sistem penjaminan mutu internal (SPMI) Universitas Perintis Indonesia."}, {"url": "http://p2amia.upertis.ac.id/", "icon": "📋", "name": "Laporan Penjaminan Mutu", "contact": "", "category": "Penjaminan Mutu", "description": "Akses laporan berkala, monitoring, evaluasi, dan audit mutu internal penyelenggaraan tridharma perguruan tinggi."}, {"url": "", "icon": "🎓", "name": "SIAKAD", "contact": "", "category": "Sistem Informasi", "description": "Sistem Informasi Akademik — portal utama untuk pengisian KRS, melihat KHS, nilai, jadwal kuliah, dan administrasi akademik mahasiswa."}, {"url": "", "icon": "🖥️", "name": "E-Learning", "contact": "", "category": "Sistem Informasi", "description": "Platform pembelajaran daring (Learning Management System) untuk akses materi kuliah, tugas, kuis, dan diskusi kelas."}, {"url": "", "icon": "📚", "name": "E-Library", "contact": "", "category": "Sistem Informasi", "description": "Katalog dan layanan perpustakaan digital online untuk mendukung referensi belajar-mengajar dan penelitian."}, {"url": "", "icon": "📁", "name": "Repository", "contact": "", "category": "Sistem Informasi", "description": "Kumpulan skripsi, tesis, jurnal ilmiah, dan publikasi penelitian civitas akademika Universitas Perintis Indonesia."}, {"url": "", "icon": "🛠️", "name": "Helpdesk IT", "contact": "", "category": "Sistem Informasi", "description": "Layanan bantuan teknis untuk akun SIAKAD, E-learning, email institusi, akses Wi-Fi, dan sistem informasi kampus lainnya."}, {"url": "https://ppid.upertis.ac.id", "icon": "📞", "name": "Layanan Informasi & Pengaduan (PPID)", "contact": "", "category": "Sistem Informasi", "description": "Layanan keterbukaan informasi publik dan portal pengaduan resmi civitas akademika."}]}', '2026-06-25 22:56:59.613234') ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, updated_at = EXCLUDED.updated_at;
INSERT INTO site_settings (key, value, updated_at) VALUES ('page_faq', '{"badge": "Frequently Asked Questions", "title_1": "Got Questions?", "title_2": "We''ve Got Answers", "subtitle": "Temukan jawaban atas pertanyaan yang paling sering diajukan seputar Universitas Perintis Indonesia.", "support_desc": "Belum menemukan jawaban yang Anda cari? Tim dukungan kami siap membantu Anda.", "support_title": "Still have questions?", "support_button": "Contact Support"}', '2026-06-18 19:14:01.636078') ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, updated_at = EXCLUDED.updated_at;
